import React, { useState } from "react";
import { Link } from "react-router-dom";

const Home = () => {

  const [searchName, setSearchName] = useState("");
  const [searchLocation, setSearchLocation] = useState("");

  // EVENTS WITH IMAGES
  const events = [
    { 
      id: 1, 
      name: "Music Concert", 
      location: "Chennai", 
      date: "May 20, 2026",
      image: "https://images.unsplash.com/photo-1501386761578-eac5c94b800a"
    },
    { 
      id: 2, 
      name: "Tech Conference", 
      location: "Bangalore", 
      date: "June 5, 2026",
      image: "https://images.unsplash.com/photo-1551836022-d5d88e9218df"
    },
    { 
      id: 3, 
      name: "Food Festival", 
      location: "Hyderabad", 
      date: "July 10, 2026",
      image: "https://images.unsplash.com/photo-1504674900247-0877df9cc836"
    },
    { 
      id: 4, 
      name: "Art Exhibition", 
      location: "Mumbai", 
      date: "August 15, 2026",
      image: "https://images.unsplash.com/photo-1513364776144-60967b0f800f"
    }
  ];

  const filteredEvents = events.filter(event =>
    event.name.toLowerCase().includes(searchName.toLowerCase()) &&
    event.location.toLowerCase().includes(searchLocation.toLowerCase())
  );

  return (
    <div className="min-h-screen bg-gray-50">

      {/* HERO SECTION */}
      <section className="bg-gradient-to-r from-blue-600 via-purple-600 to-pink-600 text-white py-24 text-center">
        <h1 className="text-5xl md:text-7xl font-bold mb-6">
          Welcome to EventHub 🎉
        </h1>

        <p className="text-xl mb-10">
          Discover and book amazing events in your city.
        </p>

        {/* SEARCH BOX */}
        <div className="bg-white/20 backdrop-blur-md rounded-xl p-6 max-w-4xl mx-auto">
          <div className="flex flex-col md:flex-row gap-4">

            <input
              type="text"
              placeholder="Search Event Name"
              value={searchName}
              onChange={(e) => setSearchName(e.target.value)}
              className="flex-1 px-5 py-3 rounded-xl text-gray-800"
            />

            <input
              type="text"
              placeholder="Search Location"
              value={searchLocation}
              onChange={(e) => setSearchLocation(e.target.value)}
              className="flex-1 px-5 py-3 rounded-xl text-gray-800"
            />

          </div>
        </div>
      </section>

      {/* EVENTS SECTION */}
      <section className="py-16 px-6">
        <h2 className="text-4xl font-bold text-center mb-12">
          Available Events
        </h2>

        <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-8">
          {filteredEvents.map(event => (
            <div 
              key={event.id} 
              className="bg-white rounded-2xl shadow-lg overflow-hidden transform hover:-translate-y-2 transition duration-300"
            >
              
              {/* IMAGE */}
              <div className="overflow-hidden">
                <img
                  src={event.image}
                  alt={event.name}
                  className="w-full h-60 object-cover hover:scale-110 transition duration-500"
                />
              </div>

              {/* CONTENT */}
              <div className="p-6">
                <h3 className="text-2xl font-bold mb-2">
                  {event.name}
                </h3>

                <p className="text-gray-600 mb-1">
                  📍 {event.location}
                </p>

                <p className="text-gray-500 mb-4">
                  📅 {event.date}
                </p>

                <button className="w-full bg-purple-600 text-white py-3 rounded-xl font-semibold hover:bg-purple-700 transition duration-300">
                  Book Now 🎟️
                </button>
              </div>

            </div>
          ))}
        </div>
      </section>

      {/* POPULAR CATEGORIES */}
      <section className="py-16 bg-gray-100">
        <h2 className="text-4xl font-bold text-center mb-12">
          Popular Categories
        </h2>

        <div className="grid md:grid-cols-2 lg:grid-cols-4 gap-8 px-6">
          {[
            { name: 'Concerts', image: "https://images.unsplash.com/photo-1501386761578-eac5c94b800a" },
            { name: 'Sports', image: "https://images.unsplash.com/photo-1517649763962-0c623066013b" },
            { name: 'Workshops', image: "https://images.unsplash.com/photo-1522202176988-66273c2fd55f" },
            { name: 'Festivals', image: "https://images.unsplash.com/photo-1492684223066-81342ee5ff30" }
          ].map((category, index) => (

            <div
              key={index}
              className="bg-white rounded-2xl shadow-lg overflow-hidden hover:shadow-2xl transform hover:-translate-y-2 transition duration-300"
            >
              <img
                src={category.image}
                alt={category.name}
                className="w-full h-48 object-cover"
              />

              <div className="p-6 text-center">
                <h3 className="text-xl font-bold mb-4">
                  {category.name}
                </h3>

                <button className="bg-purple-600 text-white px-6 py-2 rounded-full hover:bg-purple-700 transition">
                  Explore
                </button>
              </div>
            </div>

          ))}
        </div>
      </section>

      {/* CALL TO ACTION */}
      <section className="bg-gradient-to-r from-purple-600 to-pink-600 py-20 text-center text-white">
        <h2 className="text-4xl font-bold mb-6">
          Ready to Start Your Journey?
        </h2>

        <Link
          to="/register"
          className="inline-block bg-white text-purple-600 px-10 py-4 rounded-full font-bold text-lg hover:scale-105 transition duration-300"
        >
          Sign Up Free 🚀
        </Link>
      </section>

    </div>
  );
};

export default Home;
